// NEW PROJECT — set initial data
const webhook = $('Webhook — Receive Audio').item.json;
return [{
  json: {
    isNewProject: true,
    projectId: null,
    client_name: webhook.body?.client_name || webhook.client_name || 'Client',
    project_name: webhook.body?.project_name || webhook.project_name || 'New Project',
    pm_name: webhook.body?.pm_name || webhook.pm_name || '',
    pm_email: webhook.body?.pm_email || webhook.pm_email || '',
    meeting_number: 1,
    previous_requirements: [],
    previous_srd_link: null,
    srs_file_id: null,
    all_meetings: [],
    version: "1.0",
    change_log: [{
      version: "1.0",
      date: new Date().toISOString(),
      summary: "Initial SRS created"
    }]
  }
}];

const existing = $('MongoDB — Find Existing Project').item.json;
const webhook = $('Webhook — Receive Audio').item.json;

const meetingNumber = (existing.meeting_count || 1) + 1;
const newVersion = `1.${meetingNumber - 1}`;

return [{
  json: {
    isNewProject: false,
    projectId: existing._id,
    client_name: existing.client_name,
    project_name: existing.project_name,
    pm_name: existing.pm_name || webhook.body?.pm_name || '',
    pm_email: existing.pm_email || webhook.body?.pm_email || '',
    audio_url: webhook.body?.audio_url || webhook.audio_url || '',
    meeting_number: meetingNumber,
    previous_requirements: existing.requirements || [],
    previous_srd_link: existing.srd_link || null,
    srs_file_id: existing.srs_file_id || null,
    all_meetings: existing.meetings || [],
    version: newVersion,
    change_log: existing.change_log || []
  }
}];

// Merge both paths into one
const data = $input.first().json;

return [{
  json: {
    ...data
  }
}];

const data = $input.first().json;
const projectData = $('Merge Paths').item.json;
const webhookData = $('Webhook — Receive Audio').item.json;
const mergedData = $('Merge Audio + Project').first().json;

const pmName = mergedData.pm_name || webhookData.body?.pm_name || webhookData.pm_name || 'PM';
const clientName = mergedData.client_name || projectData.client_name || 'Client';

const utterances = data.utterances || [];
let transcript = '';
for (const utt of utterances) {
  const speaker = utt.speaker === 'A' ? clientName : pmName;
  const mins = String(Math.floor(utt.start / 60000)).padStart(2, '0');
  const secs = String(Math.floor((utt.start % 60000) / 1000)).padStart(2, '0');
  transcript += `[${mins}:${secs}] ${speaker}:\n"${utt.text}"\n\n`;
}

const now = new Date();
const meetingDate = now.toLocaleDateString('en-PK', {
  year: 'numeric', month: 'long', day: 'numeric'
});

return [{
  json: {
    transcript: transcript.trim(),
    meetingDate,
    meetingId: 'MTG-' + Date.now(),
    duration: data.audio_duration || 0,
    isNewProject: projectData.isNewProject,
    projectId: projectData.projectId,
    client_name: clientName,
    project_name: projectData.project_name,
    pm_email: projectData.pm_email,
    pm_name: pmName,
    meeting_number: projectData.meeting_number,
    previous_requirements: projectData.previous_requirements,
    previous_srd_link: projectData.previous_srd_link,
    all_meetings: projectData.all_meetings
  }
}];

const response = $input.first().json;
const rawText = response.choices[0].message.content;
const transcriptData = $('Format Transcript').item.json;

let cleaned = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
const start = cleaned.indexOf('{');
const end = cleaned.lastIndexOf('}');
if (start !== -1 && end !== -1) cleaned = cleaned.substring(start, end + 1);

try {
  const req = JSON.parse(cleaned);
  const funcReqs = req.functional_requirements || [];
  const nfuncReqs = req.non_functional_requirements || [];
  const conflicts = req.conflicts || [];
  const changes = req.changes_summary || {};

  return [{
    json: {
      ...req,

      // ✅ FIX — Webhook data always wins over GROK's extracted values
      project: transcriptData.project_name || req.project,
      client: transcriptData.client_name || req.client,

      // Meeting metadata
      meetingId: transcriptData.meetingId,
      meetingDate: transcriptData.meetingDate,
      meetingNumber: transcriptData.meeting_number,
      pmEmail: transcriptData.pm_email,
      transcript: transcriptData.transcript,
      duration: transcriptData.duration,
      isNewProject: transcriptData.isNewProject,
      projectId: transcriptData.projectId,
      allMeetings: transcriptData.all_meetings,

      // ✅ These also from webhook — consistent naming for MongoDB
      project_name: transcriptData.project_name,
      client_name: transcriptData.client_name,

      // Stats
      funcCount: funcReqs.length,
      nfuncCount: nfuncReqs.length,
      conflictsCount: conflicts.length,
      newReqCount: changes.new_count || 0,
      updatedReqCount: changes.updated_count || 0,
      removedReqCount: changes.removed_count || 0
    }
  }];
} catch(e) {
  return [{ json: { error: 'Parse failed', raw: rawText, ...transcriptData } }];
}

const d = $input.first().json;
const funcReqs = d.functional_requirements || [];
const nfuncReqs = d.non_functional_requirements || [];
const techConstraints = d.technical_constraints || [];
const uiReqs = d.ui_ux_requirements || [];
const techStack = d.tech_stack || [];
const conflicts = d.conflicts || [];
const changeLog = d.change_log || [];
const changesSummary = d.changes_summary || {};

const meetingNum = d.meetingNumber || d.meeting_number || 1;
const version = `1.${meetingNum - 1}`;

const priorityColor = (p) => {
  if (!p) return '#888';
  if (p.toLowerCase() === 'high') return '#C00000';
  if (p.toLowerCase() === 'medium') return '#ED7D31';
  return '#00B050';
};

const newReqs = funcReqs.filter(r => r.status === 'new').length;
const updatedReqs = funcReqs.filter(r => r.status === 'updated').length;
const unchangedReqs = funcReqs.filter(r => r.status === 'unchanged').length;

const changeLogRows = changeLog.map(entry => `
  <tr>
    <td>${entry.version || ''}</td>
    <td>${entry.date ? new Date(entry.date).toLocaleDateString() : 'N/A'}</td>
    <td>${entry.summary || ''}</td>
  </tr>`).join('');

const changesSummarySection = !d.isNewProject ? `
<div style="background:#FFF8E1;border:1px solid #FFD54F;border-radius:8px;padding:16px 24px;margin:16px 0">
  <h3 style="margin:0 0 10px;color:#E65100">📋 Changes in v${version}</h3>
  <div style="display:flex;gap:16px;margin-bottom:10px">
    <span style="background:#E8F5E9;color:#2E7D32;padding:4px 12px;border-radius:12px;font-size:13px;font-weight:bold">🆕 New: ${changesSummary.new_count || newReqs}</span>
    <span style="background:#FFF3E0;color:#E65100;padding:4px 12px;border-radius:12px;font-size:13px;font-weight:bold">✏️ Updated: ${changesSummary.updated_count || updatedReqs}</span>
    <span style="background:#F3F3F3;color:#555;padding:4px 12px;border-radius:12px;font-size:13px;font-weight:bold">✅ Unchanged: ${changesSummary.unchanged_count || unchangedReqs}</span>
  </div>
  ${changesSummary.summary_text ? `<p style="margin:0;font-size:13px;color:#555;font-style:italic">${changesSummary.summary_text}</p>` : ''}
</div>` : '';

let doc = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
  body{font-family:Arial,sans-serif;max-width:900px;margin:0 auto;padding:40px;color:#2E2E2E}
  .header{background:#1F4E79;color:white;padding:30px 40px;border-radius:8px 8px 0 0}
  .header h1{margin:0;font-size:26px}
  .header p{margin:6px 0 0;color:#B0C4D8;font-size:13px}
  .info-box{background:#f0f4f8;border:1px solid #ddd;padding:20px 40px;margin-bottom:16px}
  .info-box table{width:100%;border-collapse:collapse}
  .info-box td{padding:6px 12px;border:none;font-size:14px}
  .info-box td:first-child{font-weight:bold;color:#1F4E79;width:160px}
  .stats{display:flex;gap:16px;margin:16px 0}
  .stat{flex:1;background:white;border:1px solid #ddd;border-radius:8px;padding:16px;text-align:center}
  .stat-num{font-size:36px;font-weight:bold}
  .stat-label{font-size:12px;color:#666;margin-top:4px}
  h2{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px;margin-top:40px;font-size:18px}
  h3{color:#2E75B6;margin-top:20px;font-size:15px}
  .summary{background:#EBF3FB;border-left:4px solid #2E75B6;padding:14px 20px;border-radius:0 8px 8px 0;font-style:italic;font-size:14px;margin:12px 0}
  .req-card{border:1px solid #ddd;border-radius:8px;margin:16px 0;overflow:hidden}
  .req-header{padding:12px 20px;font-weight:bold;font-size:14px;color:white;background:#2E75B6}
  .req-header.updated{background:#E65100}
  .req-header.unchanged{background:#888}
  .req-table{width:100%;border-collapse:collapse}
  .req-table td{padding:9px 16px;border-bottom:1px solid #eee;font-size:13px;vertical-align:top}
  .req-table td:first-child{font-weight:bold;color:#1F4E79;background:#f8f9fa;width:180px}
  .req-table tr:last-child td{border-bottom:none}
  .badge{display:inline-block;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:bold;margin-left:8px}
  .badge-new{background:#E8F5E9;color:#2E7D32}
  .badge-updated{background:#FFF3E0;color:#E65100}
  .badge-unchanged{background:#F3F3F3;color:#555}
  .changelog-table{width:100%;border-collapse:collapse;margin-top:12px}
  .changelog-table th{background:#1F4E79;color:white;padding:10px 16px;text-align:left;font-size:13px}
  .changelog-table td{padding:9px 16px;border-bottom:1px solid #eee;font-size:13px}
  .changelog-table tr:nth-child(even){background:#f8f9fa}
  ul{margin:4px 0;padding-left:18px}
  ul li{padding:3px 0;font-size:13px}
  .tech-table{width:100%;border-collapse:collapse;margin-top:12px}
  .tech-table th{background:#1F4E79;color:white;padding:10px 16px;text-align:left;font-size:13px}
  .tech-table td{padding:9px 16px;border-bottom:1px solid #eee;font-size:13px}
  .tech-table tr:nth-child(even){background:#f8f9fa}
  .conflict{border:1px solid #fcc;border-radius:8px;padding:14px 20px;margin:12px 0;background:#fff5f5}
  .footer{text-align:center;color:#aaa;font-size:11px;margin-top:50px;border-top:2px solid #1F4E79;padding-top:16px}
</style>
</head>
<body>

<div class="header">
  <h1>Software Requirements Specification</h1>
  <p>${d.project || 'Project'} &nbsp;|&nbsp; v${version} &nbsp;|&nbsp; ReqAI Agent v1</p>
</div>

<div class="info-box">
  <table>
    <tr>
      <td>Project</td><td>${d.project || 'N/A'}</td>
      <td style="font-weight:bold;color:#1F4E79;width:160px">Meeting No.</td><td>#${d.meetingNumber || d.meeting_number || 1}</td>
    </tr>
    <tr>
      <td>Client</td><td>${d.client || d.client_name || 'N/A'}</td>
      <td style="font-weight:bold;color:#1F4E79">Date</td><td>${d.meetingDate || 'N/A'}</td>
    </tr>
    <tr>
      <td>Timeline</td><td>${d.timeline || 'TBD'}</td>
      <td style="font-weight:bold;color:#1F4E79">Budget</td><td>${d.budget || 'TBD'}</td>
    </tr>
    <tr>
      <td>Version</td><td><strong style="color:#1F4E79">v${version}</strong></td>
      <td style="font-weight:bold;color:#1F4E79">Document Type</td><td>${d.isNewProject ? '🆕 Initial SRS' : '✏️ Updated SRS'}</td>
    </tr>
  </table>
</div>

<div class="stats">
  <div class="stat"><div class="stat-num" style="color:#1F4E79">${funcReqs.length}</div><div class="stat-label">Functional Requirements</div></div>
  <div class="stat"><div class="stat-num" style="color:#00B050">${nfuncReqs.length}</div><div class="stat-label">Non-Functional Requirements</div></div>
  <div class="stat"><div class="stat-num" style="color:#2E75B6">${version}</div><div class="stat-label">Version</div></div>
  <div class="stat"><div class="stat-num" style="color:${conflicts.length > 0 ? '#C00000' : '#00B050'}">${conflicts.length}</div><div class="stat-label">Conflicts Detected</div></div>
</div>

${changesSummarySection}

<h2>Executive Summary</h2>
<div class="summary">${d.meeting_summary || 'No summary available.'}</div>

<h2>1. Functional Requirements</h2>`;

if (funcReqs.length === 0) {
  doc += `<p style="color:#888;font-style:italic">No functional requirements extracted.</p>`;
} else {
  for (const r of funcReqs) {
    const status = r.status || 'new';
    const badge = status === 'updated'
      ? '<span class="badge badge-updated">UPDATED</span>'
      : status === 'unchanged'
      ? '<span class="badge badge-unchanged">UNCHANGED</span>'
      : '<span class="badge badge-new">NEW</span>';
    const headerClass = status === 'updated' ? 'req-header updated' : status === 'unchanged' ? 'req-header unchanged' : 'req-header';
    const acList = (r.acceptance_criteria || []).map(ac => `<li>${ac}</li>`).join('');
    doc += `
<div class="req-card">
  <div class="${headerClass}">${r.id} — ${r.title} ${badge}</div>
  <table class="req-table">
    <tr><td>Description</td><td>${r.description}</td></tr>
    <tr><td>Priority</td><td><strong style="color:${priorityColor(r.priority)}">${r.priority || 'Medium'}</strong></td></tr>
    <tr><td>Complexity</td><td>${r.complexity || 'Medium'}</td></tr>
    <tr><td>Module</td><td>${r.module || 'General'}</td></tr>
    <tr><td>User Story</td><td><em>${r.user_story || 'N/A'}</em></td></tr>
    <tr><td>Acceptance Criteria</td><td><ul>${acList}</ul></td></tr>
  </table>
</div>`;
  }
}

doc += `<h2>2. Non-Functional Requirements</h2>`;

if (nfuncReqs.length === 0) {
  doc += `<p style="color:#888;font-style:italic">No non-functional requirements extracted.</p>`;
} else {
  for (const r of nfuncReqs) {
    doc += `
<div class="req-card">
  <div class="req-header">${r.id} — ${r.title}</div>
  <table class="req-table">
    <tr><td>Description</td><td>${r.description}</td></tr>
    <tr><td>Target</td><td>${r.target || 'TBD'}</td></tr>
    <tr><td>Priority</td><td><strong style="color:${priorityColor(r.priority)}">${r.priority || 'Medium'}</strong></td></tr>
  </table>
</div>`;
  }
}

if (techStack.length > 0) {
  doc += `<h2>3. Recommended Tech Stack</h2>
<table class="tech-table">
  <tr><th>Layer</th><th>Technology</th><th>Reason</th></tr>`;
  for (const t of techStack) {
    doc += `<tr><td>${t.layer||''}</td><td><strong>${t.technology||''}</strong></td><td>${t.reason||''}</td></tr>`;
  }
  doc += `</table>`;
}

if (techConstraints.length > 0) {
  doc += `<h2>4. Technical Constraints</h2>`;
  for (const t of techConstraints) {
    doc += `<p><strong>${t.constraint}:</strong> ${t.detail}</p>`;
  }
}

if (uiReqs.length > 0) {
  doc += `<h2>5. UI/UX Requirements</h2>`;
  for (const ui of uiReqs) {
    const comps = (ui.components || []).map(c => `<li>${c}</li>`).join('');
    doc += `<h3>Screen: ${ui.screen}</h3><ul>${comps}</ul>`;
    if (ui.notes) doc += `<p style="color:#666;font-size:13px"><em>Notes: ${ui.notes}</em></p>`;
  }
}

if (conflicts.length > 0) {
  doc += `<h2 style="color:#C00000">⚠ Conflicts — Requires Review</h2>`;
  for (const c of conflicts) {
    doc += `<div class="conflict"><strong style="color:#C00000">[${c.severity}]</strong> ${c.req1} vs ${c.req2}<br><span style="font-size:13px;color:#666">${c.description}</span></div>`;
  }
}

if (changeLog.length > 0) {
  doc += `<h2>6. Version History</h2>
<table class="changelog-table">
  <tr><th>Version</th><th>Date</th><th>Changes</th></tr>
  ${changeLogRows}
</table>`;
}

doc += `
<div class="footer">
  Generated automatically by ReqAI Agent v1 &nbsp;|&nbsp; ${d.meetingDate || ''} &nbsp;|&nbsp; v${version} &nbsp;|&nbsp; All documents saved to project history
</div>
</body></html>`;

return [{ json: { srsDocument: doc, ...d, version: version } }];

const reqData = $('Parse Requirements JSON').item.json;
const meetingFile = $('HTTP Request0').item.json;
const srsFile = $('HTTP Request1').item.json;
const webhookData = $('Webhook — Receive Audio').item.json;
const srsLink = `https://drive.google.com/file/d/${srsFile.id}/view`;
const meetingLink = `https://drive.google.com/file/d/${meetingFile.id}/view`;
const now = new Date();
const meetingDate = reqData.meetingDate || now.toLocaleDateString('en-PK', {
  year: 'numeric', month: 'long', day: 'numeric'
});
const meetingTime = now.toLocaleTimeString('en-PK', {
  hour: '2-digit', minute: '2-digit', hour12: true
});
const audioUrl = $('Merge Audio + Project').first().json.upload_url || '';
const pmName = $('Merge Audio + Project').first().json.pm_name || 
               webhookData.body?.pm_name || 
               webhookData.pm_name || 
               reqData.pm_name || '';

// Version — From Merge Paths 
const meetingNum = reqData.meetingNumber || 1;
const version = `1.${meetingNum - 1}`;

const existingChangeLog = reqData.change_log || [];
const changesSummary = reqData.changes_summary || {};

// Naya change log entry add karo
const newLogEntry = {
  version: version,
  date: now.toISOString(),
  summary: reqData.isNewProject
    ? 'Initial SRS created'
    : (changesSummary.summary_text || `Meeting #${reqData.meetingNumber} — ${changesSummary.new_count || 0} new, ${changesSummary.updated_count || 0} updated requirements`)
};

// Agar same version pehle se hai to duplicate mat karo
const alreadyExists = existingChangeLog.some(e => e.version === version);
const updatedChangeLog = alreadyExists
  ? existingChangeLog
  : [...existingChangeLog, newLogEntry];

const currentMeeting = {
  meeting_number: reqData.meetingNumber,
  meeting_id: reqData.meetingId,
  meeting_date: meetingDate,
  meeting_time: meetingTime,
  audio_url: audioUrl,
  srs_link: srsLink,
  meeting_record_link: meetingLink,
  requirements_count: reqData.funcCount || 0,
  version: version,
  changes_summary: changesSummary.summary_text || ''
};

const allMeetings = [...(reqData.allMeetings || []), currentMeeting];

return [{
  json: {
    // For routing
    isNewProject: reqData.isNewProject,
    projectId: reqData.projectId,
    // MongoDB fields
    project_name: reqData.project_name,
    client_name: reqData.client_name,
    pm_name: pmName,
    pm_email: reqData.pmEmail || reqData.pm_email || '',
    audio_url: audioUrl,
    meeting_count: reqData.meetingNumber,
    requirements: reqData.functional_requirements || [],
    srd_link: srsLink,
    meeting_record_link: meetingLink,
    srs_file_id: srsFile.id,
    meetings: allMeetings,
    last_updated: now.toISOString(),
    // Version control
    version: version,
    change_log: updatedChangeLog,
    changes_summary: changesSummary,
    // for email
    emailData: {
      pmName: pmName,
      pmEmail: reqData.pmEmail || reqData.pm_email || '',
      projectName: reqData.project_name,
      clientName: reqData.client_name,
      meetingDate: meetingDate,
      meetingNumber: reqData.meetingNumber || 1,
      srsLink,
      meetingLink,
      funcCount: reqData.funcCount || 0,
      nfuncCount: reqData.nfuncCount || 0,
      conflictsCount: reqData.conflictsCount || 0,
      isNewProject: reqData.isNewProject,
      version: version,
      changesSummary: changesSummary.summary_text || ''
    }
  }
}];

const d = $input.first().json;

const systemPrompt = `You are a senior software business analyst. Create a professional SRS document.
The transcript may be in any language (Urdu, Hindi, Arabic, etc). First translate everything to English, then extract requirements in English only.
IMPORTANT — Use EXACTLY these values in your JSON output (do not extract from transcript):
- "project": "${d.project_name}"
- "client": "${d.client_name}"
- "version": "${d.version || '1.0'}"
Return ONLY valid JSON with this exact structure — no markdown, no explanation:
{
  "project": "${d.project_name}",
  "client": "${d.client_name}",
  "version": "${d.version || '1.0'}",
  "meeting_summary": "2-3 line executive summary",
  "functional_requirements": [
    {
      "id": "FR-001",
      "title": "Requirement Title",
      "description": "Detailed description",
      "priority": "High/Medium/Low",
      "complexity": "Low/Medium/High",
      "module": "Module name",
      "user_story": "As a user, I want to...",
      "acceptance_criteria": ["Criteria 1", "Criteria 2"],
      "status": "new"
    }
  ],
  "non_functional_requirements": [
    {
      "id": "NFR-001",
      "title": "Title",
      "description": "Description",
      "target": "Measurable target",
      "priority": "High/Medium/Low",
      "status": "new"
    }
  ],
  "technical_constraints": [{"id": "TC-001", "constraint": "Title", "detail": "Detail"}],
  "ui_ux_requirements": [{"screen": "Screen name", "components": ["Component 1"], "notes": "Notes"}],
  "tech_stack": [{"layer": "Frontend/Backend/Database", "technology": "Tech name", "reason": "Why"}],
  "timeline": "estimated timeline",
  "budget": "estimated budget",
  "conflicts": [],
  "changes_summary": {
    "new_count": 0,
    "updated_count": 0,
    "removed_count": 0,
    "unchanged_count": 0,
    "summary_text": "Brief human-readable description of what changed (2-3 lines)"
  }
}`;

const userPrompt = `${d.isNewProject
  ? 'NEW PROJECT (v1.0) — Extract all requirements from this transcript. Set status: "new" for all requirements.'
  : `RETURNING CLIENT (previous v${d.previousVersion} → new v${d.version})
Previous requirements:
${JSON.stringify(d.previous_requirements)}

Compare with new transcript:
- Mark unchanged requirements as status: "unchanged"
- Mark modified requirements as status: "updated"  
- Mark brand new requirements as status: "new"
- Fill changes_summary with accurate counts and summary_text explaining what changed`}

Transcript:
${d.transcript}`;

return [{
  json: {
    ...d,
    groqBody: JSON.stringify({
      model: "llama-3.3-70b-versatile",
      max_completion_tokens: 4000,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userPrompt }
      ]
    })
  }
}];

const webhook = $('Webhook — Receive Audio').item.json;
return [{
  json: {
    query: JSON.stringify({
      project_name: webhook.body?.project_name || webhook.project_name
    })
  }
}];

const d = $input.first().json;
const boundary = 'reqai_boundary_' + Date.now();
const projectName = $('Parse Requirements JSON').item.json.project || 'Project';
const meetingNum = $('Format Transcript').first().json.meeting_number || 1;
